import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import response from './response.json';

interface CartSummary {
  itemCount: number;
  totalPrice: number;
  savings: number;
}

interface CartItem {
  name: string;
  price: number;
  quantity: number;
  savings: number;
}

interface CartData {
  cartSummary: CartSummary;
  items: CartItem[];
}

export default function Widget() {
  const cartData = response.data as CartData;
  const { cartSummary, items } = cartData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722', mb: 1 }}>
              Shopping Cart Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Items: {cartSummary.itemCount}
            </Typography>
            <Typography variant="h5" fontWeight={600} sx={{ color: '#1976D2', mt: 0.5 }}>
              Total: ${cartSummary.totalPrice.toFixed(2)}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107' }}>
              Savings: ${cartSummary.savings.toFixed(2)}
            </Typography>
          </Box>

          <Divider sx={{ borderColor: '#E0E0E0' }} />

          <Stack spacing={1.5}>
            {items.slice(0, 3).map((item, index) => (
              <Box key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2" fontWeight={500}>
                    {item.name}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    ${item.price.toFixed(2)} × {item.quantity}
                  </Typography>
                </Stack>
                {item.savings > 0 && (
                  <Typography variant="caption" sx={{ color: '#FFC107' }}>
                    Savings: ${item.savings.toFixed(2)}
                  </Typography>
                )}
              </Box>
            ))}
          </Stack>

          <Box sx={{ textAlign: 'center', mt: 1 }}>
            <Chip label="View More" variant="outlined" sx={{ fontSize: '12px', color: '#FF5722', borderColor: '#FF5722' }} />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
